public Object clone() throws CloneNotSupportedException {
  if (this == null) return null;
  Object clone = createCopy(0, getItemCount());
  if (clone instanceof Cloneable) {
    return clone;
  } else {
    throw new CloneNotSupportedException("The Object is not cloneable.");
  }
}

public Object clone() throws CloneNotSupportedException {
    Object clone = createCopy(0, Math.max(0, getItemCount() - 1));
    return clone;
}

public Object clone() throws CloneNotSupportedException {
    if (getItemCount() == 0) return createCopy(0, 0);
